// Build Cover Letter Prompt â€” Agent 2: Cover Letter Builder
// Persona + writing rules live in system_prompt (prompts tab, agent_2).
// This node injects the per-job inputs and an OUTPUT CONTRACT for plain-markdown
// letter output. Builds FROM master doc + JD (never a resume).
// Mode: Run Once for Each Item
const input = $input.item.json;
const systemPromptFromDoc = input.system_prompt || '';
const masterDoc = input.master_doc || '';
const descriptionHtml = input.description_html || '';
const company = input.company || '';
const title = input.title || '';
const provider = input.provider;
const model = input.model;
const maxTokens = input.max_tokens;

// Validation â€” Agent 2 builds the letter, so it needs the source inputs, NOT an
// existing cover_letter_markdown (that's the verifier/refiner's input).
if (!systemPromptFromDoc || systemPromptFromDoc.length < 100) {
  throw new Error(`[Agent 2] system_prompt missing or too short (${systemPromptFromDoc.length} chars). Check Prompt Loader (agent_2) and caller mapping.`);
}
if (!masterDoc || masterDoc.length < 100) {
  throw new Error(`[Agent 2] master_doc missing or too short (${masterDoc.length} chars).`);
}
if (!descriptionHtml || descriptionHtml.length < 30) {
  throw new Error(`[Agent 2] description_html (JD) missing or too short (${descriptionHtml.length} chars).`);
}

const OUTPUT_CONTRACT = `## OUTPUT CONTRACT (set by pipeline, do not override)
- Output ONLY the cover letter in markdown.
- Do NOT wrap in JSON or any envelope.
- Do NOT add commentary, preamble, or notes before or after the letter.
- Start directly with the greeting/first line of the letter.
- Every factual claim must trace to the master career document â€” invent nothing.
- Write in prose paragraphs (no bullet points or lists).
- Stay within the configured word limit.`;

const system = systemPromptFromDoc + '\n\n' + OUTPUT_CONTRACT;

const userMessage = `Write a cover letter for the following role, drawing only on facts from the candidate's master career document.

# ROLE
Company: ${company}
Title: ${title}

# JOB DESCRIPTION
${descriptionHtml}

# CANDIDATE'S MASTER CAREER DOCUMENT (ground truth â€” every claim must trace here)
${masterDoc}`;

console.log(`[Agent 2 Build Prompt] system: ${system.length} chars, user: ${userMessage.length} chars, master_doc: ${masterDoc.length}, jd: ${descriptionHtml.length}`);

return {
  json: {
    provider,
    model,
    system,
    user_message: userMessage,
    max_tokens: maxTokens,
    prompt_chars: system.length + userMessage.length
  }
};

// Set Inputs â€” Agent 2: Cover Letter Builder
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const company = strip(trigger.company);
const title = strip(trigger.title);
const descriptionHtml = strip(trigger.description_html);
const masterDoc = strip(trigger.master_doc);
const location = strip(trigger.location);
const url = strip(trigger.url);

const provider = strip(config.provider_cover_letter_drafter);
if (!provider) {
  throw new Error('[Agent 2] config.provider_cover_letter_drafter is required. Set it in your config sheet (anthropic | openai | gemini).');
}

const model = strip(config.model_cover_letter_drafter);
if (!model) {
  throw new Error('[Agent 2] config.model_cover_letter_drafter is required. Set it in your config sheet.');
}

const maxTokens = Number(config.max_tokens_cover_letter_drafter);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 2] config.max_tokens_cover_letter_drafter is required and must be a number.');
}

console.log(`[Agent 2 Set Inputs] master_doc: ${masterDoc.length} chars, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    company,
    title,
    location,
    url,
    description_html: descriptionHtml,
    master_doc: masterDoc,
    provider,
    model,
    max_tokens: maxTokens
  }
};

// Agent 2: format output as standard envelope
// Mode: Run Once for All Items
// Propagates structured error from Call LLM on failure.

const llmResponse = $input.first().json;

// Call LLM failed â€” propagate error without quality checks on empty content
if (llmResponse.success === false) {
  console.log(`[Agent 2] LLM call failed: ${llmResponse.error?.category || 'unknown'} â€” ${llmResponse.error?.message || 'no message'}`);
  return [{
    json: {
      success: false,
      result: { cover_letter_markdown: '' },
      tokens: {
        input: llmResponse.input_tokens || 0,
        output: llmResponse.output_tokens || 0
      },
      cached_input_tokens: llmResponse.cached_input_tokens || 0,
      cache_write_tokens: llmResponse.cache_write_tokens || 0,
      model_used: llmResponse.model_used || 'unknown',
      provider_used: llmResponse.provider_used || 'unknown',
      errors: [...(llmResponse.errors || [])],
      error: llmResponse.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: llmResponse.provider_used || 'unknown',
        model: llmResponse.model_used || 'unknown'
      }
    }
  }];
}

// Normal path: parse cover letter from content
const coverLetterMarkdown = (llmResponse.content || '')
  .trim()
  .replace(/^```(?:markdown|md)?\s*\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const errors = [...(llmResponse.errors || [])];
let error = null;

if (coverLetterMarkdown.length <= 100) {
  errors.push('Cover letter output suspiciously short or empty');
  error = {
    category: 'output_quality',
    type: 'short_output',
    message: 'Cover letter output suspiciously short or empty',
    provider: llmResponse.provider_used || 'unknown',
    model: llmResponse.model_used || 'unknown'
  };
}

const success = coverLetterMarkdown.length > 100;

console.log(`[Agent 2] Output: ${coverLetterMarkdown.length} chars`);
console.log(`[Agent 2] Tokens: ${llmResponse.input_tokens || 0}in + ${llmResponse.output_tokens || 0}out + ${llmResponse.cached_input_tokens || 0}cached + ${llmResponse.cache_write_tokens || 0}cache_write`);

return [{
  json: {
    success,
    result: { cover_letter_markdown: coverLetterMarkdown },
    tokens: {
      input: llmResponse.input_tokens || 0,
      output: llmResponse.output_tokens || 0
    },
    cached_input_tokens: llmResponse.cached_input_tokens || 0,
    cache_write_tokens: llmResponse.cache_write_tokens || 0,
    model_used: llmResponse.model_used || 'unknown',
    provider_used: llmResponse.provider_used || 'unknown',
    errors,
    error
  }
}];
